"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useAuth } from "@/lib/AuthContext";
import { leaderboard as lbApi } from "@/lib/apiClient";

interface LbEntry {
    rank: number;
    handle: string;
    anon_id: string;
    mood: string | null;
    points: number;
    posts_count: number;
    comments_count: number;
    listings_count: number;
}

const SCHOOL_COLORS: Record<string, string> = { ETHZ: "#1d4ed8", UZH: "#4f46e5", EPFL: "#dc2626" };
const SCHOOL_NAMES: Record<string, string> = { ETHZ: "ETH Zürich", UZH: "University of Zürich", EPFL: "EPFL" };

const TIME_FILTERS = [
    { label: "Today", value: "today" },
    { label: "This Week", value: "week" },
    { label: "All-time", value: "all-time" },
];

export default function LeaderboardPage() {
    const { user, isLoadingAuth } = useAuth();
    const router = useRouter();
    const searchParams = useSearchParams();
    const schoolCode = searchParams.get("school") || user?.school_id || "ETHZ";

    const [entries, setEntries] = useState<LbEntry[]>([]);
    const [myRank, setMyRank] = useState<LbEntry | null>(null);
    const [loading, setLoading] = useState(true);
    const [timeWindow, setTimeWindow] = useState("all-time");

    const primary = SCHOOL_COLORS[schoolCode] ?? "#1d4ed8";

    useEffect(() => {
        if (!isLoadingAuth && !user) router.replace("/login");
    }, [user, isLoadingAuth, router]);

    useEffect(() => {
        if (!user) return;
        setLoading(true);
        lbApi.get(schoolCode, timeWindow).then((data: any) => {
            setEntries(data.leaderboard ?? []);
            setMyRank(data.myRank ?? null);
        }).catch(console.error).finally(() => setLoading(false));
    }, [schoolCode, timeWindow, user]);

    return (
        <div className="min-h-screen pb-20 bg-slate-50">
            {/* Top bar */}
            <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-100 shadow-sm">
                <div className="max-w-xl mx-auto px-4 py-3 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Link href="/feed" className="w-8 h-8 rounded-xl bg-slate-100 flex items-center justify-center text-slate-600 hover:bg-slate-200 transition-colors">
                            ←
                        </Link>
                        <span className="font-black text-slate-900 text-sm">🏆 Leaderboard</span>
                        <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full font-medium">{schoolCode}</span>
                    </div>
                </div>
            </div>

            <div className="max-w-xl mx-auto px-4 py-6">
                {/* Header */}
                <div className="flex items-center justify-between mb-6">
                    <div>
                        <h1 className="text-2xl font-black text-slate-900">Leaderboard</h1>
                        <p className="text-sm text-slate-500">Top contributors at {SCHOOL_NAMES[schoolCode] ?? schoolCode}</p>
                    </div>
                    <div className="flex bg-slate-100 p-1 rounded-xl">
                        {TIME_FILTERS.map((f) => (
                            <button
                                key={f.value}
                                onClick={() => setTimeWindow(f.value)}
                                className={`px-3 py-1.5 text-xs font-bold rounded-lg transition-all ${timeWindow === f.value ? "bg-white text-slate-900 shadow-sm" : "text-slate-400 hover:text-slate-600"}`}
                            >
                                {f.label}
                            </button>
                        ))}
                    </div>
                </div>

                {/* My rank card */}
                {myRank && (
                    <div className="mb-6 p-0.5 rounded-3xl" style={{ background: `linear-gradient(135deg, ${primary}, ${primary}99)` }}>
                        <div className="bg-white rounded-[22px] p-5">
                            <div className="flex items-center justify-between">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-lg font-black" style={{ backgroundColor: `${primary}20`, color: primary }}>
                                        #{myRank.rank}
                                    </div>
                                    <div>
                                        <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-0.5">My Rank</p>
                                        <h3 className="text-lg font-black text-slate-900">{myRank.handle}</h3>
                                    </div>
                                </div>
                                <div className="text-right">
                                    <p className="text-2xl font-black text-slate-900">{myRank.points}</p>
                                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-0.5">Total Pts</p>
                                </div>
                            </div>
                            <div className="grid grid-cols-3 gap-2 mt-4 pt-4 border-t border-slate-50">
                                <div className="text-center"><p className="text-sm font-bold">{myRank.posts_count}</p><p className="text-[9px] font-bold text-slate-400 uppercase">Posts</p></div>
                                <div className="text-center border-x border-slate-50"><p className="text-sm font-bold">{myRank.comments_count}</p><p className="text-[9px] font-bold text-slate-400 uppercase">Comments</p></div>
                                <div className="text-center"><p className="text-sm font-bold">{myRank.listings_count}</p><p className="text-[9px] font-bold text-slate-400 uppercase">Listings</p></div>
                            </div>
                        </div>
                    </div>
                )}

                {/* List */}
                <div className="bg-white rounded-3xl border border-slate-100 shadow-sm overflow-hidden">
                    {loading ? (
                        <div className="divide-y divide-slate-50">
                            {Array(8).fill(0).map((_, i) => (
                                <div key={i} className="p-4 flex items-center justify-between animate-pulse">
                                    <div className="flex items-center gap-4"><div className="w-8 h-8 rounded-lg bg-slate-100" /><div className="h-4 w-24 bg-slate-100 rounded" /></div>
                                    <div className="h-4 w-12 bg-slate-100 rounded" />
                                </div>
                            ))}
                        </div>
                    ) : entries.length === 0 ? (
                        <div className="py-20 text-center">
                            <p className="text-slate-400 font-medium">No data for this period</p>
                        </div>
                    ) : (
                        <div className="divide-y divide-slate-50">
                            {entries.map((entry, idx) => (
                                <div
                                    key={entry.anon_id}
                                    className={`p-4 flex items-center justify-between hover:bg-slate-50/50 transition-colors ${entry.anon_id === myRank?.anon_id ? "bg-amber-50/30" : ""}`}
                                >
                                    <div className="flex items-center gap-3 min-w-0">
                                        <div className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-black shrink-0 ${entry.rank === 1 ? "bg-amber-100 text-amber-600" : entry.rank === 2 ? "bg-slate-200 text-slate-600" : entry.rank === 3 ? "bg-orange-100 text-orange-600" : "bg-slate-50 text-slate-400"
                                            }`}>
                                            {entry.rank}
                                        </div>
                                        <div className="min-w-0">
                                            <p className="text-sm font-bold text-slate-900 truncate">{entry.handle}</p>
                                            <p className="text-[9px] text-slate-400">
                                                {entry.posts_count}p · {entry.comments_count}c · {entry.listings_count}l
                                            </p>
                                        </div>
                                    </div>
                                    <div className="flex items-center gap-2 shrink-0">
                                        <div className="text-right">
                                            <p className="text-sm font-black text-slate-900">{entry.points}</p>
                                            <p className="text-[8px] font-bold text-slate-400 uppercase">pts</p>
                                        </div>
                                        {entry.rank <= 3 && <span>{entry.rank === 1 ? "🥇" : entry.rank === 2 ? "🥈" : "🥉"}</span>}
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}
